const COLORS=['#1a56db','#0d7c66','#9333ea','#c2410c','#0e7490','#b91c1c','#4f46e5','#15803d','#a16207','#6d28d9','#0369a1','#be185d'];
const DS_NOTES=[{id:'s1',name:'Patient Information',instructions:'Name, Age, Gender, K number, Room Number.',rules:''},{id:'s2',name:'Chief Complaint',instructions:'Primary reason for the visit.',rules:''},{id:'s3',name:'History of Present Illness (HPI)',instructions:'Begin with "Patient was admitted for..." Describe timeline.',rules:'Include dates ONLY if user explicitly states them.'},{id:'s4',name:'Hospital Course',instructions:'Events, exams, labs, imaging during hospitalization.',rules:'Include dates ONLY if user provides them.'},{id:'s5',name:'Current Status',instructions:'Begin with "Patient was evaluated..."',rules:''},{id:'s6',name:'Physical Examination',instructions:'General, HEENT, Neck, CV, Resp, Abdomen, Extremities, Neuro, Skin.',rules:'Use normal defaults. Replace only if user provides abnormal findings.'},{id:'s7',name:'Assessments',instructions:'Numbered clinical assessments.',rules:'Must be numbered.'},{id:'s8',name:'Laboratories',instructions:'CBC, BMP, LFTs, Coagulation, Other.',rules:''},{id:'s9',name:'Medications',instructions:'Current inpatient, PRN, Home medications.',rules:''},{id:'s10',name:'Plan',instructions:'Numbered treatment plan.',rules:'Include "Likely discharge" at end.'},{id:'s11',name:'Recommendations',instructions:'Follow-up, Monitoring, Additional testing.',rules:''},{id:'s12',name:'Consultants',instructions:'List consulting specialists.',rules:''}];
const DS_ADM=[{id:'a1',name:'Patient Information',instructions:'Name, Age, Gender, Date.',rules:''},{id:'a2',name:'Chief Complaint',instructions:'Primary reason for admission.',rules:''},{id:'a3',name:'History of Present Illness',instructions:'Detailed narrative.',rules:''},{id:'a4',name:'Past Medical History',instructions:'Prior conditions, surgeries.',rules:''},{id:'a5',name:'Medications',instructions:'Current medications, doses.',rules:''},{id:'a6',name:'Social History',instructions:'Tobacco, alcohol, drugs, occupation.',rules:''},{id:'a7',name:'Review of Systems',instructions:'Systematic review by organ system.',rules:''},{id:'a8',name:'Physical Examination',instructions:'Complete exam by system.',rules:''},{id:'a9',name:'Assessments',instructions:'Numbered assessments.',rules:''},{id:'a10',name:'Plan',instructions:'Numbered plan items.',rules:''},{id:'a11',name:'Summary',instructions:'Brief summary.',rules:''}];
const DEF_GENERAL_RULES='- Use the exact structure below in order.\n- If information is missing, write "Not provided"\n- Professional medical English. Concise but accurate.\n- Return ONLY clean HTML: <h2> for section titles, <p> for content, <strong> for labels. No code blocks.\n- Use narrative prose style.';
const DOPTS={abnormalOnly:false,bullets:false,narrative:true,detail:'medium',missing:'Not provided',generalRules:DEF_GENERAL_RULES,typo:{h2:{size:16,bold:true,color:'#000000',underline:false},strong:{size:14,bold:true,color:'#000000',underline:false},p:{size:14,bold:false,color:'#000000',underline:false}}};
const DEFAULT_SHEETS=[{id:'admission',name:'Admission',color:'#0d7c66',builtIn:true,sections:JSON.parse(JSON.stringify(DS_ADM)),options:{...DOPTS,generalRules:DEF_GENERAL_RULES}},{id:'notes',name:'Medical Notes',color:'#1a56db',builtIn:true,sections:JSON.parse(JSON.stringify(DS_NOTES)),options:{...DOPTS,generalRules:DEF_GENERAL_RULES}}];

let currentSheetId='notes',pbSheetId='notes';
let structuredText='',reportGenerated=false,currentCaseId=null,currentInput='',hasUnsavedEdits=false,saveDebounceTimer=null,currentCaseType='notes',savedDraft='',caseImages=[];
let confirmCb=null;
let medicalNotesCount=0;

function loadS(){try{const s=localStorage.getItem('mn_v4');if(s){const d=JSON.parse(s);if(d.sheets&&d.sheets.length){const ai=d.sheets.findIndex(x=>x.id==='admission'),ni=d.sheets.findIndex(x=>x.id==='notes');if(ni===0&&ai>0){const adm=d.sheets.splice(ai,1)[0];d.sheets.unshift(adm);}return d;}}}catch{}return{email:'',darkMode:false,language:'en',spellingLevel:'medium',voiceCorrection:'medium',doctor:{name:'Dr. Miguel Rivas',license:'',specialty:'',phone:'',email:'',npi:''},hospital:{name:'',dept:'',address:'',phone:''},sheets:JSON.parse(JSON.stringify(DEFAULT_SHEETS))};}
function saveS(s){try{localStorage.setItem('mn_v4',JSON.stringify(s));}catch{}}
let S=loadS();

function getSheet(id){return S.sheets.find(s=>s.id===id)||S.sheets[0];}
function curSheet(){return getSheet(currentSheetId);}

function buildPrompt(sheetId){const sh=getSheet(sheetId);const o=sh.options||DOPTS;const secs=sh.sections||[];const lang=S.language==='es'?'Spanish':'English';const spell=S.spellingLevel||'medium';let p='You are a medical documentation assistant.\nConvert unstructured clinical notes into a standardized medical report.\nOUTPUT LANGUAGE: '+lang+'\n- Always use professional medical language.\n- Spelling/grammar correction level: '+spell.toUpperCase()+'. '+(spell==='high'?'Fix ALL spelling and grammar errors aggressively.':spell==='low'?'Fix only critical misspellings.':'Fix obvious spelling and grammar errors.')+'\n\nRULES:\n';
if(o.generalRules&&o.generalRules.trim())p+=o.generalRules.trim()+'\n';
if(o.abnormalOnly)p+='- Include ONLY abnormal findings.\n';if(o.bullets)p+='- Use bullet points (<ul><li>) for lists.\n';
p+='- Detail level: '+((o.detail||'medium').toUpperCase())+'.\n';
p+='\nSTRUCTURE:\n';secs.forEach((s,i)=>{p+='\n'+(i+1)+'. '+s.name+'\n';if(s.instructions)p+='   Instructions: '+s.instructions+'\n';if(s.rules)p+='   Rules: '+s.rules+'\n';});
p+='\nINPUT:\n{{USER_TEXT}}\n\nOUTPUT: Return ONLY the structured report as HTML in '+lang+'.';return p;}

function getActivePrompt(){return buildPrompt(currentSheetId);}
function esc(s){return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}

/* ═══ CONFIRM DIALOG ═══ */
function showConfirm(msg,cb){document.getElementById('confirmMsg').innerHTML=msg;confirmCb=cb;document.getElementById('confirmOverlay').classList.add('active');}
function closeConfirm(yes){document.getElementById('confirmOverlay').classList.remove('active');if(confirmCb)confirmCb(yes);confirmCb=null;}

/* ═══ DARK MODE ═══ */
function applyDarkMode(on){document.documentElement.classList.toggle('dark',on);const sw=document.getElementById('switchDark');if(sw)sw.classList.toggle('on',on);}
function toggleDarkSwitch(){const sw=document.getElementById('switchDark');sw.classList.toggle('on');applyDarkMode(sw.classList.contains('on'));}
applyDarkMode(S.darkMode);

/* ═══ APPLY SHEET THEME ═══ */
function applySheetTheme(sh){const c=sh.color||'#1a56db';document.documentElement.style.setProperty('--primary',c);document.documentElement.style.setProperty('--primary-hover',c);document.documentElement.style.setProperty('--primary-light',c+'12');document.documentElement.style.setProperty('--header-accent',c);document.documentElement.style.setProperty('--report-h2',c);document.documentElement.style.setProperty('--sheet-color',c);document.documentElement.style.setProperty('--sidebar-active-bg',c+'1a');document.documentElement.style.setProperty('--sidebar-active-border',c);document.documentElement.style.setProperty('--sidebar-hover-border',c+'66');document.documentElement.style.setProperty('--sidebar-btn-bg',c+'26');document.documentElement.style.setProperty('--sidebar-btn-color',c);document.documentElement.style.setProperty('--sidebar-btn-border',c+'40');
document.getElementById('mainTitle').textContent=sh.name;document.getElementById('mainSubtitle').textContent='AI-powered clinical documentation';
const micLabel=document.querySelector('.mn-mic-label');if(micLabel)micLabel.textContent=sh.name+' Notes';
const docEl=document.getElementById('headerDoctor');if(docEl)docEl.textContent=(S.doctor&&S.doctor.name)?S.doctor.name:'';}

function switchMode(sheetId){hideSpecialPanels();document.querySelectorAll('#tabNotepad,#tabImageReader,#tabImageBank').forEach(b=>b.classList.remove('active'));currentSheetId=sheetId;const sh=curSheet();applySheetTheme(sh);renderModeTabs();
// Auto-filter sidebar to current sheet type
const ft=document.getElementById('filterType');if(ft){ft.value=sheetId;renderSidebar();}
updateFilterTypeOptions();}

/* ═══ MODE TABS ═══ */
function renderModeTabs(){const c=document.getElementById('modeTabs');c.innerHTML=S.sheets.map(sh=>{const active=sh.id===currentSheetId?' active':'';return'<button class="mn-mode-tab'+active+'" data-mode="'+sh.id+'" onclick="switchMode(\''+sh.id+'\')"><span class="mn-tab-dot" style="background:'+sh.color+'"></span>'+esc(sh.name)+'</button>';}).join('');}

/* ═══ SHEET MANAGER ═══ */
let editingSheetId=null;
function openSheetModal(editId){editingSheetId=editId||null;document.getElementById('sheetModalTitle').textContent=editId?'Edit Sheet':'New Sheet';document.getElementById('sheetModalSave').textContent=editId?'Save':'Create';const sh=editId?getSheet(editId):null;document.getElementById('sheetNameInput').value=sh?sh.name:'';const row=document.getElementById('colorRow');row.innerHTML=COLORS.map(c=>'<div class="mn-color-swatch'+(sh&&sh.color===c?' selected':(!sh&&c===COLORS[S.sheets.length%COLORS.length]?' selected':''))+'" style="background:'+c+'" data-color="'+c+'" onclick="pickColor(this)"></div>').join('');document.getElementById('sheetModalOverlay').classList.add('active');document.getElementById('sheetNameInput').focus();}
function closeSheetModal(){document.getElementById('sheetModalOverlay').classList.remove('active');editingSheetId=null;}
function pickColor(el){document.querySelectorAll('.mn-color-swatch').forEach(s=>s.classList.remove('selected'));el.classList.add('selected');}
function saveSheetModal(){const name=document.getElementById('sheetNameInput').value.trim();if(!name){toast('Enter a name.',true);return;}const sel=document.querySelector('.mn-color-swatch.selected');const color=sel?sel.dataset.color:COLORS[0];if(editingSheetId){const sh=getSheet(editingSheetId);sh.name=name;sh.color=color;}else{const id='sheet_'+Date.now();S.sheets.push({id,name,color,builtIn:false,sections:[{id:'s1',name:'Patient Information',instructions:'Name, Age, Gender, Date.',rules:''},{id:'s2',name:'Chief Complaint',instructions:'Primary reason.',rules:''},{id:'s3',name:'History of Present Illness',instructions:'Detailed narrative.',rules:''},{id:'s4',name:'Physical Examination',instructions:'Complete exam.',rules:''},{id:'s5',name:'Assessments',instructions:'Numbered assessments.',rules:''},{id:'s6',name:'Plan',instructions:'Numbered plan items.',rules:''}],options:{...DOPTS,generalRules:DEF_GENERAL_RULES}});switchMode(id);}saveS(S);renderModeTabs();updateFilterTypeOptions();closeSheetModal();toast(editingSheetId?'Sheet updated.':'Sheet created.');}
function deleteSheet(id){const sh=getSheet(id);if(sh.builtIn){toast('Cannot delete built-in sheets.',true);return;}showConfirm('Delete sheet <strong>"'+esc(sh.name)+'"</strong> and all its prompt config? Cases in history will remain.',ok=>{if(!ok)return;S.sheets=S.sheets.filter(s=>s.id!==id);if(currentSheetId===id)switchMode(S.sheets[0].id);saveS(S);renderModeTabs();updateFilterTypeOptions();toast('Sheet deleted.');});}

/* ═══ PROMPT BUILDER ═══ */
let dragSrcIdx=null;
function switchPBSheet(id){pbSheetId=id;renderPBSheetTabs();loadPBO();renderPBS();}
function renderPBSheetTabs(){document.getElementById('pbSheetTabs').innerHTML=S.sheets.map(sh=>{const del=!sh.builtIn?' <span style="margin-left:4px;cursor:pointer;opacity:.5;font-size:11px" onclick="event.stopPropagation();deleteSheet(\''+sh.id+'\')" title="Delete sheet">&times;</span>':'';return'<button class="pb-sheet-tab'+(sh.id===pbSheetId?' active':'')+'" style="'+(sh.id===pbSheetId?'border-color:'+sh.color+';color:'+sh.color+';background:'+sh.color+'0d':'')+'" onclick="switchPBSheet(\''+sh.id+'\')"><span class="pb-sheet-dot" style="background:'+sh.color+'"></span>'+esc(sh.name)+del+'</button>';}).join('');}
function gSh(){return getSheet(pbSheetId);}
function gSecs(){return gSh().sections;}
function gOpts(){return gSh().options||(gSh().options={...DOPTS,generalRules:''});}
function loadPBO(){const o=gOpts();document.getElementById('pbOptAbnormal').checked=!!o.abnormalOnly;document.getElementById('pbOptBullets').checked=!!o.bullets;document.getElementById('pbOptNarrative').checked=!!o.narrative;document.getElementById('pbOptDetail').value=o.detail||'medium';document.getElementById('pbOptMissing').value=o.missing||'Not provided';document.getElementById('pbGeneralRules').value=o.generalRules!=null?o.generalRules:DEF_GENERAL_RULES;const t=o.typo||DOPTS.typo;const h2=t.h2||{size:16,bold:true,color:'#000000',underline:false};const st=t.strong||{size:14,bold:true,color:'#000000',underline:false};const pp=t.p||{size:14,bold:false,color:'#000000',underline:false};if(typeof h2==='number'){document.getElementById('typoH2').value=h2;document.getElementById('typoH2Bold').checked=true;document.getElementById('typoH2Color').value='#000000';document.getElementById('typoH2Under').checked=false;document.getElementById('typoStrong').value=typeof st==='number'?st:14;document.getElementById('typoStrongBold').checked=true;document.getElementById('typoStrongColor').value='#000000';document.getElementById('typoStrongUnder').checked=false;document.getElementById('typoP').value=typeof pp==='number'?pp:14;document.getElementById('typoPBold').checked=false;document.getElementById('typoPColor').value='#000000';document.getElementById('typoPUnder').checked=false;}else{document.getElementById('typoH2').value=h2.size||16;document.getElementById('typoH2Bold').checked=h2.bold!==false;document.getElementById('typoH2Color').value=h2.color||'#000000';document.getElementById('typoH2Under').checked=!!h2.underline;document.getElementById('typoStrong').value=st.size||14;document.getElementById('typoStrongBold').checked=st.bold!==false;document.getElementById('typoStrongColor').value=st.color||'#000000';document.getElementById('typoStrongUnder').checked=!!st.underline;document.getElementById('typoP').value=pp.size||14;document.getElementById('typoPBold').checked=!!pp.bold;document.getElementById('typoPColor').value=pp.color||'#000000';document.getElementById('typoPUnder').checked=!!pp.underline;}}
function savePBO(){const o=gOpts();o.abnormalOnly=document.getElementById('pbOptAbnormal').checked;o.bullets=document.getElementById('pbOptBullets').checked;o.narrative=document.getElementById('pbOptNarrative').checked;o.detail=document.getElementById('pbOptDetail').value;o.missing=document.getElementById('pbOptMissing').value||'Not provided';o.generalRules=document.getElementById('pbGeneralRules').value;o.typo={h2:{size:+document.getElementById('typoH2').value||16,bold:document.getElementById('typoH2Bold').checked,color:document.getElementById('typoH2Color').value,underline:document.getElementById('typoH2Under').checked},strong:{size:+document.getElementById('typoStrong').value||14,bold:document.getElementById('typoStrongBold').checked,color:document.getElementById('typoStrongColor').value,underline:document.getElementById('typoStrongUnder').checked},p:{size:+document.getElementById('typoP').value||14,bold:document.getElementById('typoPBold').checked,color:document.getElementById('typoPColor').value,underline:document.getElementById('typoPUnder').checked}};}
function renderPBS(){const secs=gSecs();const sh=gSh();document.getElementById('pbSections').innerHTML=secs.map((s,i)=>'<div class="pb-section" draggable="true" data-idx="'+i+'" ondragstart="pbDS(event)" ondragover="pbDO(event)" ondrop="pbDD(event)" ondragend="pbDE(event)" ondragleave="pbDL(event)"><div class="pb-section-header"><div class="pb-section-grip"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="9" cy="6" r="1.5"/><circle cx="15" cy="6" r="1.5"/><circle cx="9" cy="12" r="1.5"/><circle cx="15" cy="12" r="1.5"/><circle cx="9" cy="18" r="1.5"/><circle cx="15" cy="18" r="1.5"/></svg></div><div class="pb-section-num" style="background:'+sh.color+'">'+(i+1)+'</div><div class="pb-section-name">'+esc(s.name)+'</div><div class="pb-section-actions"><button onclick="tSB('+i+')"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M11 4H4a2 2 0 00-2 2v14a2 2 0 002 2h14a2 2 0 002-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 013 3L12 15l-4 1 1-4 9.5-9.5z"/></svg></button><button class="pb-del" onclick="delSec('+i+')"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="3 6 5 6 21 6"/><path d="M19 6v14a2 2 0 01-2 2H7a2 2 0 01-2-2V6m3 0V4a2 2 0 012-2h4a2 2 0 012 2v2"/></svg></button></div></div><div class="pb-section-body" id="pbB'+i+'"><div class="pb-field"><div class="pb-field-label">Section Name</div><input class="pb-input" value="'+esc(s.name)+'" oninput="uSec('+i+',\'name\',this.value)"></div><div class="pb-field"><div class="pb-field-label">Instructions for AI</div><textarea class="pb-textarea" oninput="uSec('+i+',\'instructions\',this.value)">'+esc(s.instructions)+'</textarea></div><div class="pb-field"><div class="pb-field-label">Rules / Conditions</div><textarea class="pb-textarea" style="min-height:45px" oninput="uSec('+i+',\'rules\',this.value)">'+esc(s.rules)+'</textarea></div></div></div>').join('');}
function tSB(i){document.getElementById('pbB'+i).classList.toggle('open');}
function uSec(i,f,v){gSecs()[i][f]=v;if(f==='name')renderPBS();}
function delSec(i){showConfirm('Delete section <strong>"'+esc(gSecs()[i].name)+'"</strong>?',ok=>{if(!ok)return;gSecs().splice(i,1);renderPBS();});}
function addSection(){const s=gSecs();s.push({id:'s_'+Date.now(),name:'New Section',instructions:'',rules:''});renderPBS();setTimeout(()=>{const el=document.getElementById('pbB'+(s.length-1));if(el)el.classList.add('open');},50);}
function resetCurrentPB(){const sh=gSh();const label=sh.name;showConfirm('Reset <strong>all sections and options</strong> for "'+esc(label)+'" to defaults? This cannot be undone.',ok=>{if(!ok)return;const def=sh.id==='notes'?DS_NOTES:sh.id==='admission'?DS_ADM:[{id:'s1',name:'Patient Information',instructions:'Name, Age, Gender, Date.',rules:''},{id:'s2',name:'Chief Complaint',instructions:'Primary reason.',rules:''},{id:'s3',name:'Plan',instructions:'Numbered plan items.',rules:''}];sh.sections=JSON.parse(JSON.stringify(def));sh.options={...DOPTS,generalRules:DEF_GENERAL_RULES};loadPBO();renderPBS();toast('Reset to defaults.');});}
function togglePreview(){savePBO();const el=document.getElementById('pbPreview');el.classList.toggle('open');if(el.classList.contains('open'))el.textContent=buildPrompt(pbSheetId);}
function pbDS(e){dragSrcIdx=+e.currentTarget.dataset.idx;e.currentTarget.classList.add('dragging');e.dataTransfer.effectAllowed='move';}
function pbDO(e){e.preventDefault();e.dataTransfer.dropEffect='move';e.currentTarget.classList.add('drag-over');}
function pbDL(e){e.currentTarget.classList.remove('drag-over');}
function pbDE(){document.querySelectorAll('.pb-section').forEach(s=>s.classList.remove('dragging','drag-over'));}
function pbDD(e){e.preventDefault();const t=+e.currentTarget.dataset.idx;e.currentTarget.classList.remove('drag-over');if(dragSrcIdx===null||dragSrcIdx===t)return;const s=gSecs(),moved=s.splice(dragSrcIdx,1)[0];s.splice(t,0,moved);renderPBS();}

/* ═══ SETTINGS ═══ */
function showSettingsTab(tab){document.querySelectorAll('.mn-stab').forEach(t=>t.classList.remove('active'));document.querySelectorAll('.mn-settings-page').forEach(p=>p.classList.remove('active'));document.getElementById('settings-'+tab).classList.add('active');const tabs=document.querySelectorAll('.mn-stab');({general:0,doctor:1,prompts:2})[tab]!==undefined&&tabs[({general:0,doctor:1,prompts:2})[tab]]?.classList.add('active');if(tab==='prompts'){pbSheetId=currentSheetId;renderPBSheetTabs();loadPBO();renderPBS();}}
function openSettings(){document.getElementById('settingsEmail').value=S.email||'';document.getElementById('switchDark').classList.toggle('on',!!S.darkMode);document.getElementById('settingsLang').value=S.language||'en';document.getElementById('settingsSpelling').value=S.spellingLevel||'medium';document.getElementById('settingsVoiceCorrection').value=S.voiceCorrection||'medium';const d=S.doctor||{};document.getElementById('docName').value=d.name||'Dr. Miguel Rivas';document.getElementById('docLicense').value=d.license||'';document.getElementById('docSpecialty').value=d.specialty||'';document.getElementById('docPhone').value=d.phone||'';document.getElementById('docEmail').value=d.email||'';document.getElementById('docNPI').value=d.npi||'';const h=S.hospital||{};document.getElementById('hospName').value=h.name||'';document.getElementById('hospDept').value=h.dept||'';document.getElementById('hospAddress').value=h.address||'';document.getElementById('hospPhone').value=h.phone||'';showSettingsTab('general');document.getElementById('settingsOverlay').classList.add('active');}
function closeSettings(){document.getElementById('settingsOverlay').classList.remove('active');}
function saveSettings(){savePBO();S.email=document.getElementById('settingsEmail').value.trim();S.darkMode=document.getElementById('switchDark').classList.contains('on');S.language=document.getElementById('settingsLang').value;S.spellingLevel=document.getElementById('settingsSpelling').value;S.voiceCorrection=document.getElementById('settingsVoiceCorrection').value;S.doctor={name:document.getElementById('docName').value.trim(),license:document.getElementById('docLicense').value.trim(),specialty:document.getElementById('docSpecialty').value.trim(),phone:document.getElementById('docPhone').value.trim(),email:document.getElementById('docEmail').value.trim(),npi:document.getElementById('docNPI').value.trim()};S.hospital={name:document.getElementById('hospName').value.trim(),dept:document.getElementById('hospDept').value.trim(),address:document.getElementById('hospAddress').value.trim(),phone:document.getElementById('hospPhone').value.trim()};saveS(S);applyDarkMode(S.darkMode);applySheetTheme(curSheet());closeSettings();toast('Settings saved.');}

function toggleDateFilters(){const d=document.getElementById('filterDates');const b=document.getElementById('filterToggleBtn');d.classList.toggle('open');b.classList.toggle('open');}

