function newCase(){autoSaveDraft();document.getElementById('welcomeScreen').style.display='none';document.getElementById('mainWorkarea').style.display='block';document.getElementById('reportContent').innerHTML='';document.getElementById('outputSection').classList.remove('active');document.getElementById('editHint').classList.remove('active');document.getElementById('editPanel').classList.remove('active');document.getElementById('btnSaveEdits').style.display='none';document.getElementById('saveIndicator').classList.remove('active');document.getElementById('draftBanner').classList.remove('active');document.getElementById('btnFollowup').style.display='none';document.getElementById('followupContainer').innerHTML='';document.getElementById('followupPromptArea').style.display='none';structuredText='';reportGenerated=false;currentCaseId=null;currentInput='';hasUnsavedEdits=false;clearCaseImages();document.getElementById('inputToggle').style.display='none';document.getElementById('inputBody').classList.remove('collapsed');document.querySelectorAll('.mn-sidebar-item').forEach(i=>i.classList.remove('active'));
// Restore draft for this sheet if exists
const draftKey='draft_'+currentSheetId;const saved=localStorage.getItem(draftKey);if(saved){document.getElementById('clinicalInput').value=saved;document.getElementById('charCount').textContent=saved.length;}else{document.getElementById('clinicalInput').value='';document.getElementById('charCount').textContent='0';}
toast('New report.');if(window.innerWidth<=768)toggleSidebar();}

emailjs.init('g9QLDsRVRgREUkNxz');
function toggleEmailPanel(){const p=document.getElementById('emailPanel');p.classList.toggle('active');if(p.classList.contains('active')){const ef=document.getElementById('emailTo');if(!ef.value.trim())ef.value=S.email||'';ef.focus();}}
async function sendEmail(){const to=document.getElementById('emailTo').value.trim();if(!to||!to.includes('@')){toast('Enter a valid email.',true);return;}const lH=document.getElementById('reportContent').innerHTML;if(!lH.trim()){toast('No report.',true);return;}document.getElementById('btnSend').disabled=true;document.getElementById('btnSend').textContent='Sending...';try{await emailjs.send('service_juj0v5c','template_rw4cwfl',{to_email:to,subject:'Medical Report — '+(extractTitle(lH)||'Report'),report_html:lH});toast('Sent to '+to);document.getElementById('emailPanel').classList.remove('active');}catch(e){toast('Error: '+(e.text||e.message||e),true);}document.getElementById('btnSend').disabled=false;document.getElementById('btnSend').textContent='Send';}

function getLiveReportHTML(){return document.getElementById('reportContent').innerHTML;}
function getDoctorStampHTML(){const d=S.doctor||{},h=S.hospital||{};const name=d.name||'Dr. Miguel Rivas';let l=['<strong>'+esc(name)+'</strong>'];if(d.specialty)l.push(esc(d.specialty));if(d.license)l.push('License: '+esc(d.license));if(d.npi)l.push('NPI: '+esc(d.npi));if(d.phone)l.push('Tel: '+esc(d.phone));if(d.email)l.push(esc(d.email));if(h.name){l.push('');l.push('<strong>'+esc(h.name)+'</strong>');if(h.dept)l.push(esc(h.dept));if(h.address)l.push(esc(h.address));if(h.phone)l.push('Tel: '+esc(h.phone));}return l.join('<br>');}
function applyReportTypo(){const sh=curSheet();const t=sh.options?.typo||DOPTS.typo;const h2=typeof t.h2==='number'?{size:t.h2,bold:true,color:'#000000',underline:false}:t.h2;const st=typeof t.strong==='number'?{size:t.strong,bold:true,color:'#000000',underline:false}:t.strong;const pp=typeof t.p==='number'?{size:t.p,bold:false,color:'#000000',underline:false}:t.p;const rep=document.getElementById('reportContent');rep.querySelectorAll('h2').forEach(el=>{el.style.fontSize=h2.size+'px';el.style.fontWeight=h2.bold?'700':'400';el.style.color=h2.color||'';el.style.textDecoration=h2.underline?'underline':'none';});rep.querySelectorAll('strong').forEach(el=>{el.style.fontSize=st.size+'px';el.style.fontWeight=st.bold?'700':'400';el.style.color=st.color||'';el.style.textDecoration=st.underline?'underline':'none';});rep.querySelectorAll('p').forEach(el=>{el.style.fontSize=pp.size+'px';el.style.fontWeight=pp.bold?'700':'400';el.style.color=pp.color||'';el.style.textDecoration=pp.underline?'underline':'none';});}

document.getElementById('reportContent').addEventListener('input',function(){hasUnsavedEdits=true;structuredText=this.innerHTML;document.getElementById('btnSaveEdits').style.display='inline-flex';const ind=document.getElementById('saveIndicator');ind.classList.add('active','saving');document.getElementById('saveIndicatorText').textContent='Unsaved...';clearTimeout(saveDebounceTimer);saveDebounceTimer=setTimeout(()=>autoSave(),2000);});
async function autoSave(){if(!currentCaseId||!hasUnsavedEdits)return;try{const h=getLiveReportHTML();await saveCase(currentCaseId,extractTitle(h),currentInput,h,currentCaseType);hasUnsavedEdits=false;document.getElementById('saveIndicator').classList.remove('saving');document.getElementById('saveIndicatorText').textContent='Saved';document.getElementById('btnSaveEdits').style.display='none';renderSidebar();setTimeout(()=>document.getElementById('saveIndicator').classList.remove('active'),2500);}catch{document.getElementById('saveIndicatorText').textContent='Failed';}}
async function saveManualEdits(){if(!currentCaseId)return;try{await saveCase(currentCaseId,extractTitle(getLiveReportHTML()),currentInput,getLiveReportHTML(),currentCaseType);hasUnsavedEdits=false;document.getElementById('btnSaveEdits').style.display='none';renderSidebar();toast('Saved.');}catch(e){toast('Error: '+e.message,true);}}
function dismissHint(){document.getElementById('editHint').classList.remove('active');}
async function callAPI(c){const r=await fetch(PROXY,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({model:'claude-sonnet-4-20250514',max_tokens:4096,messages:[{role:'user',content:c}]})});if(!r.ok){const e=await r.json().catch(()=>({}));throw new Error(e.error?.message||'API error '+r.status);}const d=await r.json();let h=d.content.map(b=>b.text||'').join('');return h.replace(/```html?/g,'').replace(/```/g,'').trim();}
async function saveCase(id,title,input,output,type){await fetch(PROXY+'/save',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({id,title,input,output,type:type||'notes',timestamp:Date.now()})});}
async function loadHistory(){try{return await(await fetch(PROXY+'/history')).json();}catch{return[];}}
async function deleteCase(id){await fetch(PROXY+'/history/'+id,{method:'DELETE'});}
function extractTitle(html){const t=document.createElement('div');t.innerHTML=html;for(const p of t.querySelectorAll('p')){const x=p.textContent;if((x.includes('Name:')||x.includes('name:'))&&!x.includes('Not provided')){const n=x.split(':').slice(1).join(':').trim();if(n&&n!=='Not provided')return n;}}return'Medical Report';}
function extractMeta(html){const t=document.createElement('div');t.innerHTML=html;let name='',age='',complaint='';for(const p of t.querySelectorAll('p')){const x=p.textContent.trim();if(x.startsWith('Name:'))name=x.replace('Name:','').trim();else if(x.startsWith('Age:'))age=x.replace('Age:','').trim();}for(const h2 of t.querySelectorAll('h2')){if(h2.textContent.includes('Chief Complaint')){let n=h2.nextElementSibling;if(n&&n.tagName==='P')complaint=n.textContent.trim().substring(0,100);break;}}return{name,age,complaint};}

async function renderSidebar(){const cases=await loadHistory();const list=document.getElementById('sidebarList');const fType=document.getElementById('filterType').value;const fFrom=document.getElementById('filterFrom').value;const fTo=document.getElementById('filterTo').value;const fKey=(document.getElementById('filterKeyword').value||'').trim().toLowerCase();let filtered=cases;if(fType&&fType!=='all')filtered=filtered.filter(c=>(c.type||'notes')===fType);if(fFrom){const d=new Date(fFrom).getTime();filtered=filtered.filter(c=>c.timestamp>=d);}if(fTo){const d=new Date(fTo).getTime()+86400000;filtered=filtered.filter(c=>c.timestamp<d);}if(fKey)filtered=filtered.filter(c=>{const hay=((c.title||'')+(c.input||'')+(c.output||'')).toLowerCase();return hay.includes(fKey);});
if(!filtered.length){list.innerHTML='<div class="mn-sidebar-empty">'+(cases.length?'No matching cases.':'No saved cases yet.')+'</div>';return;}
list.innerHTML=filtered.map(c=>{const d=new Date(c.timestamp),ds=d.toLocaleDateString('en-US',{month:'short',day:'numeric'}),ts=d.toLocaleTimeString('en-US',{hour:'2-digit',minute:'2-digit'});const meta=extractMeta(c.output||'');const act=currentCaseId===c.id?' active':'';const type=c.type||'notes';const sh=getSheet(type);const color=sh?sh.color:'#888';const label=sh?sh.name.substring(0,4).toUpperCase():type.substring(0,4).toUpperCase();let mH='';if(meta.name&&meta.name!=='Not provided')mH+='<span>'+esc(meta.name)+'</span>';if(meta.complaint&&meta.complaint!=='Not provided')mH+='<span><span class="mn-meta-label">CC</span>'+esc(meta.complaint)+'</span>';const pv=c.input?esc(c.input.substring(0,80))+(c.input.length>80?'...':''):'';return'<div class="mn-sidebar-item'+act+'" onclick="loadCase(\''+c.id+'\')"><div class="mn-sidebar-item-title"><span class="mn-type-badge" style="background:'+color+'22;color:'+color+'">'+label+'</span>'+esc(c.title||'Untitled')+'</div><div class="mn-sidebar-item-date">'+ds+' '+ts+'</div>'+(mH?'<div class="mn-sidebar-item-meta">'+mH+'</div>':'')+'<div class="mn-sidebar-item-preview">'+pv+'</div><div class="mn-sidebar-item-btns" onclick="event.stopPropagation()"><button class="mn-sbtn-regen" onclick="regenCase(\''+c.id+'\')">Re</button><button class="mn-sbtn-del" onclick="deleteCaseUI(\''+c.id+'\')">X</button></div></div>';}).join('');}

async function loadCase(id){try{autoSaveDraft();saveDraftIfNeeded();const c=await(await fetch(PROXY+'/history/'+id)).json();currentCaseId=c.id;currentInput=c.input;structuredText=c.output;reportGenerated=true;hasUnsavedEdits=false;currentCaseType=c.type||'notes';if(S.sheets.find(s=>s.id===currentCaseType))switchMode(currentCaseType);document.getElementById('welcomeScreen').style.display='none';document.getElementById('mainWorkarea').style.display='block';document.getElementById('clinicalInput').value=c.input;document.getElementById('charCount').textContent=c.input.length;document.getElementById('reportContent').innerHTML=c.output;applyReportTypo();caseImages=extractImages(c.output);renderImageThumbs();document.getElementById('outputSection').classList.add('active');document.getElementById('editHint').classList.add('active');const sh=getSheet(currentCaseType);document.getElementById('outputTypeBadge').textContent=sh?sh.name:currentCaseType;document.getElementById('btnSaveEdits').style.display='none';document.getElementById('inputToggle').style.display='flex';document.getElementById('inputBody').classList.add('collapsed');document.getElementById('inputToggle').classList.add('collapsed');document.getElementById('toggleLabel').textContent='Show Notes';document.getElementById('btnFollowup').style.display='inline-flex';document.getElementById('followupContainer').innerHTML='';document.getElementById('followupPromptArea').style.display='none';loadPersonalNote();renderSidebar();showChatToggle();loadChatForCase(currentCaseId);if(chatOpen)renderChatMessages();toast('Case loaded.');document.getElementById('outputSection').scrollIntoView({behavior:'smooth',block:'start'});if(window.innerWidth<=768)toggleSidebar();}catch(e){toast('Error: '+e.message,true);}}
async function regenCase(id){try{saveDraftIfNeeded();const c=await(await fetch(PROXY+'/history/'+id)).json();currentInput=c.input;currentCaseId=c.id;currentCaseType=c.type||'notes';if(S.sheets.find(s=>s.id===currentCaseType))switchMode(currentCaseType);document.getElementById('clinicalInput').value=c.input;document.getElementById('charCount').textContent=c.input.length;document.getElementById('inputBody').classList.remove('collapsed');document.getElementById('draftBanner').classList.remove('active');toast('Regenerating...');if(window.innerWidth<=768)toggleSidebar();await generateReport();}catch(e){toast('Error: '+e.message,true);}}
async function deleteCaseUI(id){showConfirm('Delete this case permanently?',async ok=>{if(!ok)return;try{await deleteCase(id);if(currentCaseId===id)doClearAll();toast('Deleted.');renderSidebar();}catch(e){toast('Error: '+e.message,true);}});}

let recognition=null,isRecording=false;
let voiceMediaRecorder=null,voiceAudioChunks=[],voiceStream=null,voiceTimerInterval=null,voiceSeconds=0,voiceAudioContext=null,voiceAnalyser=null,voiceIsRecording=false,voiceLiveText='',voiceLiveInterim='',voiceLiveRec=null;
function toggleMic(){toggleVoiceRecorder();}
function toggleVoiceRecorder(){if(voiceIsRecording){stopVoiceRecorder();return;}startVoiceRecorder();}
async function startVoiceRecorder(){if(!('webkitSpeechRecognition' in window)&&!('SpeechRecognition' in window)){toast('Voice input not supported on this browser. Please use Chrome.',true);return;}try{voiceStream=await navigator.mediaDevices.getUserMedia({audio:true});voiceAudioChunks=[];voiceSeconds=0;voiceIsRecording=true;voiceLiveText='';document.getElementById('voiceTimer').textContent='0:00';document.getElementById('voiceRecorder').classList.add('active');document.getElementById('btnMic').classList.add('recording');document.getElementById('micStatus').textContent='';voiceTimerInterval=setInterval(()=>{voiceSeconds++;const m=Math.floor(voiceSeconds/60),s=voiceSeconds%60;document.getElementById('voiceTimer').textContent=m+':'+(s<10?'0':'')+s;},1000);setupVoiceSilenceDetection(voiceStream);startBackgroundTranscription();}catch(e){toast('Microphone access denied.',true);}}
function setupVoiceSilenceDetection(stream){voiceAudioContext=new(window.AudioContext||window.webkitAudioContext)();voiceAnalyser=voiceAudioContext.createAnalyser();const source=voiceAudioContext.createMediaStreamSource(stream);source.connect(voiceAnalyser);voiceAnalyser.fftSize=512;const data=new Uint8Array(voiceAnalyser.frequencyBinCount);let silentSince=null;const wave=document.getElementById('voiceWave');function check(){if(!voiceIsRecording)return;voiceAnalyser.getByteFrequencyData(data);const avg=data.reduce((a,b)=>a+b,0)/data.length;if(avg>15){silentSince=null;wave.classList.add('speaking');updateWaveBars(data);}else{if(!silentSince)silentSince=Date.now();wave.classList.remove('speaking');if(Date.now()-silentSince>=15000){stopVoiceRecorder();return;}}requestAnimationFrame(check);}check();}
function updateWaveBars(data){const bars=document.querySelectorAll('#voiceWave .mn-voice-bar');const step=Math.floor(data.length/bars.length);bars.forEach((bar,i)=>{const val=data[i*step]||0;const h=Math.max(4,Math.min(32,(val/255)*32));bar.style.height=h+'px';});}
function startBackgroundTranscription(){if(!('webkitSpeechRecognition' in window)&&!('SpeechRecognition' in window))return;const SR=window.SpeechRecognition||window.webkitSpeechRecognition;voiceLiveRec=new SR();voiceLiveRec.continuous=true;voiceLiveRec.interimResults=true;voiceLiveRec.lang='en-US';voiceLiveRec.onresult=e=>{for(let i=e.resultIndex;i<e.results.length;i++){if(e.results[i].isFinal){voiceLiveText+=e.results[i][0].transcript+' ';voiceLiveInterim='';}else{voiceLiveInterim=e.results[i][0].transcript;}}};voiceLiveRec.onend=()=>{if(voiceIsRecording){setTimeout(()=>{if(voiceIsRecording)try{voiceLiveRec.start();}catch(ex){}},200);}};voiceLiveRec.onerror=e=>{if(e.error==='no-speech'){return;}if(e.error==='audio-capture'||e.error==='not-allowed'){toast('Microphone access error.',true);stopVoiceRecorder();}};try{voiceLiveRec.start();}catch(ex){}}
function stopBackgroundTranscription(){try{if(voiceLiveRec){voiceLiveRec.onend=null;voiceLiveRec.stop();voiceLiveRec=null;}}catch(ex){}}
function attachMiniMic(textareaId){const ta=document.getElementById(textareaId);if(!ta||ta.parentElement.querySelector('.mn-mini-mic'))return;const btn=document.createElement('button');btn.className='mn-mini-mic';btn.type='button';btn.title='Dictate';btn.innerHTML='<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="16" height="16"><path d="M12 1a3 3 0 00-3 3v8a3 3 0 006 0V4a3 3 0 00-3-3z"/><path d="M19 10v2a7 7 0 01-14 0v-2"/><line x1="12" y1="19" x2="12" y2="23"/><line x1="8" y1="23" x2="16" y2="23"/></svg>';btn.onclick=function(e){e.preventDefault();e.stopPropagation();startMiniDictation(ta,btn);};ta.parentElement.style.position='relative';ta.parentElement.insertBefore(btn,ta);}
function startMiniDictation(ta,btn){if(btn.classList.contains('recording')){stopMiniDictation(btn);return;}if(!('webkitSpeechRecognition' in window)&&!('SpeechRecognition' in window)){toast('Voice not supported.',true);return;}const SR=window.SpeechRecognition||window.webkitSpeechRecognition;const rec=new SR();rec.continuous=true;rec.interimResults=true;rec.lang='en-US';btn._miniRec=rec;btn._miniText='';btn._miniInterim='';btn.classList.add('recording');btn.title='Stop dictation';rec.onresult=e=>{for(let i=e.resultIndex;i<e.results.length;i++){if(e.results[i].isFinal){btn._miniText+=e.results[i][0].transcript+' ';btn._miniInterim='';}else{btn._miniInterim=e.results[i][0].transcript;}}};rec.onend=()=>{if(btn.classList.contains('recording')){setTimeout(()=>{if(btn.classList.contains('recording'))try{rec.start();}catch(ex){}},200);}};rec.onerror=e=>{if(e.error==='no-speech'){return;}if(e.error==='audio-capture'||e.error==='not-allowed'){stopMiniDictation(btn);toast('Microphone access error.',true);}};rec.start();btn._silenceTimer=setTimeout(()=>{stopMiniDictation(btn);},120000);}
async function stopMiniDictation(btn){btn.classList.remove('recording');btn.title='Dictate';if(btn._silenceTimer){clearTimeout(btn._silenceTimer);btn._silenceTimer=null;}const rec=btn._miniRec;if(rec){rec.onend=null;try{rec.stop();}catch(ex){}}const rawText=((btn._miniText||'')+(btn._miniInterim?' '+btn._miniInterim:'')).trim();btn._miniText='';btn._miniInterim='';if(!rawText){toast('No speech detected.',true);return;}const ta=btn.nextElementSibling;if(!ta)return;const oldPlaceholder=ta.placeholder;ta.placeholder='Correcting for medical context...';ta.disabled=true;try{const resp=await fetch(PROXY,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({model:'claude-sonnet-4-20250514',max_tokens:4096,messages:[{role:'user',content:getVoiceCorrectionPrompt(rawText)}]})});if(!resp.ok)throw new Error('Correction failed');const data=await resp.json();const corrected=data.content.map(b=>b.text||'').join('').trim();const existing=ta.value.trim();ta.value=existing?(existing+'\n\n'+corrected):corrected;toast('Voice transcribed & corrected!');}catch(e){ta.value=ta.value+(ta.value?'\n\n':'')+rawText;toast('Correction failed, raw text added.',true);}finally{ta.placeholder=oldPlaceholder;ta.disabled=false;ta.focus();}}function stopVoiceRecorder(){voiceIsRecording=false;if(voiceTimerInterval){clearInterval(voiceTimerInterval);voiceTimerInterval=null;}stopBackgroundTranscription();processVoiceAudio();if(voiceStream){voiceStream.getTracks().forEach(t=>t.stop());voiceStream=null;}if(voiceAudioContext){voiceAudioContext.close();voiceAudioContext=null;}document.getElementById('voiceRecorder').classList.remove('active');document.getElementById('btnMic').classList.remove('recording');document.getElementById('micStatus').textContent='';}
async function processVoiceAudio(){const rawText=(voiceLiveText+(voiceLiveInterim?' '+voiceLiveInterim:'')).trim();voiceLiveText='';voiceLiveInterim='';if(!rawText){toast('No speech detected. Try again.',true);return;}document.getElementById('voiceProcessing').classList.add('active');document.getElementById('voiceProcText').textContent='Correcting for medical context...';try{const correctResp=await fetch(PROXY,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({model:'claude-sonnet-4-20250514',max_tokens:4096,messages:[{role:'user',content:getVoiceCorrectionPrompt(rawText)}]})});if(!correctResp.ok)throw new Error('Correction failed');const correctData=await correctResp.json();const correctedText=correctData.content.map(b=>b.text||'').join('').trim();const ta=document.getElementById('clinicalInput');const existing=ta.value.trim();ta.value=existing?(existing+'\n\n'+correctedText):correctedText;document.getElementById('charCount').textContent=ta.value.length;toast('Voice transcribed & corrected!');localStorage.setItem('draft_'+currentSheetId,ta.value);}catch(e){toast('Error: '+e.message,true);}finally{document.getElementById('voiceProcessing').classList.remove('active');}}function toggleExportMenu(){document.getElementById('exportWrap').classList.toggle('open');}
function closeExportMenu(){document.getElementById('exportWrap')?.classList.remove('open');}
document.addEventListener('click',function(e){if(!e.target.closest('#exportWrap'))closeExportMenu();if(!e.target.closest('#notepadExportWrap'))closeNotepadExport();if(!e.target.closest('#readerExportWrap'))closeReaderExport();});
function getVoiceCorrectionPrompt(rawText){const level=S&&S.voiceCorrection||'medium';const prompts={low:'You are a medical transcription editor. Lightly clean the following dictated text.\n\nRULES (LOW — stay very faithful to original):\n1. Fix only clear speech recognition errors (e.g. "high pertension"→"hypertension")\n2. Add minimal punctuation (periods at sentence ends)\n3. Do NOT rephrase, restructure, or reword anything\n4. Do NOT change word order or phrasing\n5. Keep the same language as the input (English or Spanish)\n6. Return ONLY the corrected text, nothing else',medium:'You are a medical transcription editor. Correct the following dictated text with moderate adjustments.\n\nRULES (MODERATE):\n1. Fix speech recognition errors and obvious medical terminology mistakes\n2. Fix clear grammar errors and add proper punctuation\n3. Keep the speaker\'s own words and phrasing — do NOT rephrase unnecessarily\n4. Maintain all clinical details exactly as stated\n5. Keep the same language as the input (English or Spanish)\n6. Return ONLY the corrected text, nothing else',high:'You are a medical transcription editor. Thoroughly correct the following dictated text.\n\nRULES (HIGH):\n1. Fix all grammar, punctuation, and sentence structure\n2. Correct all medical terminology\n3. Use professional medical language\n4. IMPORTANT: Keep all the same clinical information — do NOT add, remove, or change any medical facts\n5. Keep the same language as the input (English or Spanish)\n6. Return ONLY the corrected text, nothing else'};return(prompts[level]||prompts.medium)+'\n\nDictated text:\n'+rawText;}
function handleImgFiles(files){const promises=Array.from(files).map(f=>compressImage(f,1200,.78).then(dataUrl=>({dataUrl,name:f.name})));Promise.all(promises).then(imgs=>{caseImages.push(...imgs);renderImageThumbs();document.getElementById('imgFileInput').value='';if(reportGenerated)syncImagesInReport();});}
function compressImage(file,maxPx,quality){return new Promise(resolve=>{const img=new Image();const url=URL.createObjectURL(file);img.onload=()=>{URL.revokeObjectURL(url);let w=img.width,h=img.height;if(w>maxPx||h>maxPx){if(w>h){h=Math.round(h*maxPx/w);w=maxPx;}else{w=Math.round(w*maxPx/h);h=maxPx;}}const c=document.createElement('canvas');c.width=w;c.height=h;c.getContext('2d').drawImage(img,0,0,w,h);resolve(c.toDataURL('image/jpeg',quality));};img.src=url;});}
function renderImageThumbs(){const t=document.getElementById('imgThumbs');if(!t)return;t.innerHTML=caseImages.map((img,i)=>`<div class="mn-img-thumb-wrap"><img class="mn-img-thumb" src="${img.dataUrl}" onclick="openImgPreview('${img.dataUrl}')" title="${esc(img.name)}"><button class="mn-img-remove" onclick="removeImage(${i})" title="Remove">\xd7</button></div>`).join('');}
function removeImage(idx){caseImages.splice(idx,1);renderImageThumbs();if(reportGenerated)syncImagesInReport();}
function openImgPreview(src){const lb=document.createElement('div');lb.className='mn-img-lightbox';lb.innerHTML=`<button class="mn-img-lightbox-close" onclick="event.stopPropagation();document.body.removeChild(this.closest('.mn-img-lightbox'))">\xd7</button><img src="${src}">`;lb.onclick=()=>document.body.removeChild(lb);document.body.appendChild(lb);}
function getImagesHTML(){if(!caseImages.length)return'';const imgs=caseImages.map((img,i)=>`<img src="${img.dataUrl}" onclick="openImgPreview('${img.dataUrl}')" alt="${esc(img.name)}" style="max-width:100%;max-height:280px;border-radius:8px;border:1px solid var(--border);cursor:pointer;object-fit:contain">`).join('');return`<div class="mn-case-images"><div class="mn-case-images-title"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="15" height="15"><rect x="3" y="3" width="18" height="18" rx="2"/><circle cx="8.5" cy="8.5" r="1.5"/><polyline points="21 15 16 10 5 21"/></svg> Clinical Images</div><div class="mn-case-images-grid">${imgs}</div></div>`;}
function extractImages(outputHtml){try{const div=document.createElement('div');div.innerHTML=outputHtml;const grid=div.querySelector('.mn-case-images-grid');if(!grid)return[];return Array.from(grid.querySelectorAll('img')).map((el,i)=>({dataUrl:el.src,name:el.alt||('Image '+(i+1))}));}catch{return[];}}
function syncImagesInReport(){const rc=document.getElementById('reportContent');if(!rc)return;const ex=rc.querySelector('.mn-case-images');if(ex)ex.remove();if(caseImages.length)rc.insertAdjacentHTML('beforeend',getImagesHTML());hasUnsavedEdits=true;}
function clearCaseImages(){caseImages=[];const t=document.getElementById('imgThumbs');if(t)t.innerHTML='';}
function goHome(){showWelcome();}
function hideSpecialPanels(){['notepadPanel','imageReaderPanel','imageBankPanel'].forEach(id=>{const el=document.getElementById(id);if(el)el.style.display='none';});}
function switchSpecialMode(mode){hideSpecialPanels();document.getElementById('welcomeScreen').style.display='none';document.getElementById('mainWorkarea').style.display='none';document.querySelectorAll('.mn-mode-tab').forEach(b=>b.classList.remove('active'));const ids={notepad:'notepadPanel','image-reader':'imageReaderPanel','image-bank':'imageBankPanel'};const tabIds={notepad:'tabNotepad','image-reader':'tabImageReader','image-bank':'tabImageBank'};const el=document.getElementById(ids[mode]);if(el)el.style.display='block';const btn=document.getElementById(tabIds[mode]);if(btn)btn.classList.add('active');if(mode==='notepad')loadNotepad();if(mode==='image-bank')loadImageBank();}
function loadNotepad(){const saved=localStorage.getItem('mn_notepad')||'';const ta=document.getElementById('notepadContent');if(ta){ta.value=saved;document.getElementById('notepadChars').textContent=saved.length;}}
function saveNotepad(){const txt=document.getElementById('notepadContent').value;localStorage.setItem('mn_notepad',txt);document.getElementById('notepadChars').textContent=txt.length;}
async function correctNotepad(){const txt=document.getElementById('notepadContent').value.trim();if(!txt){toast('Write something first.',true);return;}const outArea=document.getElementById('notepadOutput');const outContent=document.getElementById('notepadOutputContent');outArea.style.display='block';outContent.innerHTML='<span style="color:var(--text-muted)">Correcting...</span>';try{const resp=await fetch(PROXY,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({model:'claude-sonnet-4-20250514',max_tokens:4096,messages:[{role:'user',content:'Correct the following notes for grammar, spelling, and clarity. Keep the same language (English or Spanish). Keep the same meaning and tone. Return ONLY the corrected text:\n\n'+txt}]})});if(!resp.ok)throw new Error('failed');const d=await resp.json();const corrected=d.content.map(b=>b.text||'').join('').trim();outContent.innerText=corrected;toast('Corrected!');}catch(e){outContent.innerHTML='<span style="color:var(--danger)">Error correcting text.</span>';toast('Error.',true);}}
function clearNotepad(){document.getElementById('notepadContent').value='';document.getElementById('notepadChars').textContent='0';document.getElementById('notepadOutput').style.display='none';localStorage.removeItem('mn_notepad');toast('Cleared.');}
function toggleNotepadExport(){document.getElementById('notepadExportWrap').classList.toggle('open');}
function closeNotepadExport(){document.getElementById('notepadExportWrap')?.classList.remove('open');}
async function downloadNotepadPDF(){const outEl=document.getElementById('notepadOutputContent');const inEl=document.getElementById('notepadContent');const hasOut=outEl.innerText.trim().length>0;if(!hasOut&&!inEl.value.trim()){toast('Nothing to export.',true);return;}toast('Preparing PDF...');try{if(hasOut){const canvas=await html2canvas(outEl,{scale:2,backgroundColor:'#fff'});const{jsPDF}=window.jspdf;const pdf=new jsPDF('p','mm','a4');const pw=pdf.internal.pageSize.getWidth()-20;const ih=canvas.height*pw/canvas.width;pdf.addImage(canvas.toDataURL('image/png'),'PNG',10,10,pw,ih);pdf.save('Notepad.pdf');}else{const{jsPDF}=window.jspdf;const pdf=new jsPDF('p','mm','a4');const lines=pdf.splitTextToSize(inEl.value,170);pdf.setFont('helvetica');pdf.setFontSize(11);pdf.text(lines,20,20);pdf.save('Notepad.pdf');}toast('PDF ready.');}catch{toast('PDF error.',true);}}
function downloadNotepadDocx(){const outEl=document.getElementById('notepadOutputContent');const inEl=document.getElementById('notepadContent');const content=outEl.innerText.trim()||inEl.value;if(!content.trim()){toast('Nothing to export.',true);return;}const html=content.split('\n').map(l=>'<p>'+(esc(l)||'&nbsp;')+'</p>').join('');const doc='<!DOCTYPE html><html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:w="urn:schemas-microsoft-com:office:word" xmlns="http://www.w3.org/TR/REC-html40"><head><meta charset="UTF-8"><style>@page{size:letter;margin:2.54cm}body{font-family:Calibri,sans-serif;font-size:11pt;line-height:1.6}p{margin:3pt 0}</style></head><body>'+html+'</body></html>';const blob=new Blob(['\ufeff'+doc],{type:'application/msword'});const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download='Notepad.doc';document.body.appendChild(a);a.click();setTimeout(()=>{document.body.removeChild(a);URL.revokeObjectURL(url);},250);toast('Word ready.');}
let readerImageDataUrl=null;
function handleReaderFile(file){if(!file)return;const reader=new FileReader();reader.onload=e=>{readerImageDataUrl=e.target.result;document.getElementById('readerPreviewImg').src=readerImageDataUrl;document.getElementById('readerPreviewArea').style.display='block';document.getElementById('readerResultArea').style.display='none';};reader.readAsDataURL(file);}
function buildImagePrompt(context){if(context)return'Context provided: '+context+'\n\nBased on this context, transcribe or describe the content of this image as accurately and completely as possible. Preserve all values, units, and data exactly as they appear. If it is a medical document, maintain the exact format. Return ONLY the transcription or description.';return'Look at this image carefully.\n- If it contains text, numbers, tables, lab values, prescriptions, reports or any readable content: transcribe it faithfully and completely, preserving all values, units, dates, and structure.\n- If it appears to be a medical imaging study (X-ray, CT, MRI, ultrasound, echocardiogram, pathology slide, angiography, etc.) without readable text: respond with exactly the word: IMAGING_DETECTED\n\nReturn ONLY the transcription or IMAGING_DETECTED.';}
async function callVisionAPI(dataUrl,promptText){const match=dataUrl.match(/^data:([^;]+);base64,(.+)$/);if(!match)throw new Error('Invalid image');const mediaType=match[1];const b64=match[2];const r=await fetch(PROXY,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({model:'claude-sonnet-4-20250514',max_tokens:4096,messages:[{role:'user',content:[{type:'image',source:{type:'base64',media_type:mediaType,data:b64}},{type:'text',text:promptText}]}]})});if(!r.ok)throw new Error('API error '+r.status);const d=await r.json();return d.content.map(b=>b.text||'').join('').trim();}
async function readImageContent(){if(!readerImageDataUrl){toast('Upload an image first.',true);return;}const context=(document.getElementById('readerContextArea')?.value||'').trim();document.getElementById('readerLoader').style.display='block';document.getElementById('readerResultArea').style.display='none';try{const text=await callVisionAPI(readerImageDataUrl,buildImagePrompt(context));if(text==='IMAGING_DETECTED'){document.getElementById('imagingContextModal').classList.add('open');window._imagingTarget='reader';}else{document.getElementById('readerResult').innerText=text;document.getElementById('readerResultArea').style.display='block';toast('Image read!');}}catch(e){toast('Error: '+e.message,true);}finally{document.getElementById('readerLoader').style.display='none';}}
function clearImageReader(){readerImageDataUrl=null;document.getElementById('readerFileInput').value='';document.getElementById('readerPreviewArea').style.display='none';document.getElementById('readerResultArea').style.display='none';const ca=document.getElementById('readerContextArea');if(ca){ca.value='';ca.style.display='none';}const ct=document.getElementById('readerContextToggle');if(ct)ct.textContent='+ Add context (optional)';}
function toggleReaderContext(){const ca=document.getElementById('readerContextArea');const ct=document.getElementById('readerContextToggle');if(!ca)return;const vis=ca.style.display!=='none';ca.style.display=vis?'none':'block';ct.textContent=vis?'+ Add context (optional)':'- Hide context';if(!vis)ca.focus();}
let inlineReaderDataUrl=null;
function handleInlineReaderFile(file){if(!file)return;const reader=new FileReader();reader.onload=e=>{inlineReaderDataUrl=e.target.result;document.getElementById('inlineReaderImg').src=inlineReaderDataUrl;document.getElementById('inlineReader').style.display='block';document.getElementById('inlineReaderResultArea').style.display='none';document.getElementById('btnAddToNotes').style.display='none';document.getElementById('btnTranscribeInline').style.display='';document.getElementById('inlineReaderContext').value='';document.getElementById('inlineReaderContext').style.display='none';document.getElementById('inlineContextToggle').textContent='+ Add context (optional)';document.getElementById('inlineReaderInput').value='';};reader.readAsDataURL(file);}
function toggleInlineContext(){const ca=document.getElementById('inlineReaderContext');const ct=document.getElementById('inlineContextToggle');const vis=ca.style.display!=='none';ca.style.display=vis?'none':'block';ct.textContent=vis?'+ Add context (optional)':'- Hide context';if(!vis)ca.focus();}
async function transcribeInlineImage(){if(!inlineReaderDataUrl){toast('No image loaded.',true);return;}const context=(document.getElementById('inlineReaderContext').value||'').trim();document.getElementById('inlineReaderLoader').style.display='block';document.getElementById('inlineReaderResultArea').style.display='none';document.getElementById('btnTranscribeInline').disabled=true;try{const text=await callVisionAPI(inlineReaderDataUrl,buildImagePrompt(context));if(text==='IMAGING_DETECTED'){document.getElementById('imagingContextModal').classList.add('open');window._imagingTarget='inline';}else{document.getElementById('inlineReaderResult').value=text;document.getElementById('inlineReaderResultArea').style.display='block';document.getElementById('btnAddToNotes').style.display='';toast('Image read!');}}catch(e){toast('Error: '+e.message,true);}finally{document.getElementById('inlineReaderLoader').style.display='none';document.getElementById('btnTranscribeInline').disabled=false;}}
function appendInlineTranscription(){const text=document.getElementById('inlineReaderResult').value.trim();if(!text){toast('No transcription to add.',true);return;}const ta=document.getElementById('clinicalInput');const existing=ta.value.trim();ta.value=existing?(existing+'\n\n'+text):text;document.getElementById('charCount').textContent=ta.value.length;if(!reportGenerated)localStorage.setItem('draft_'+currentSheetId,ta.value);toast('Added to notes!');clearInlineReader();}
function clearInlineReader(){inlineReaderDataUrl=null;document.getElementById('inlineReader').style.display='none';document.getElementById('inlineReaderInput').value='';document.getElementById('inlineReaderResultArea').style.display='none';document.getElementById('btnAddToNotes').style.display='none';}
function closeImagingModal(){document.getElementById('imagingContextModal').classList.remove('open');window._imagingTarget=null;}
async function interpretWithImagingContext(){const context=document.getElementById('imagingContextInput').value.trim();if(!context){toast('Please provide context first.',true);return;}closeImagingModal();const target=window._imagingTarget;if(target==='inline'){document.getElementById('inlineReaderContext').value=context;document.getElementById('inlineReaderContext').style.display='block';document.getElementById('inlineContextToggle').textContent='- Hide context';await transcribeInlineImage();}else{document.getElementById('readerContextArea').value=context;document.getElementById('readerContextArea').style.display='block';document.getElementById('readerContextToggle').textContent='- Hide context';await readImageContent();}}
function copyReaderResult(){const t=document.getElementById('readerResult').innerText;navigator.clipboard.writeText(t).then(()=>toast('Copied!')).catch(()=>toast('Copy failed.',true));}
function toggleReaderExport(){document.getElementById('readerExportWrap').classList.toggle('open');}
function closeReaderExport(){document.getElementById('readerExportWrap')?.classList.remove('open');}
async function downloadReaderPDF(){const el=document.getElementById('readerResult');if(!el.innerText.trim()){toast('Nothing to export.',true);return;}toast('Preparing PDF...');try{const canvas=await html2canvas(el,{scale:2,backgroundColor:'#fff'});const{jsPDF}=window.jspdf;const pdf=new jsPDF('p','mm','a4');const pw=pdf.internal.pageSize.getWidth()-20;const ih=canvas.height*pw/canvas.width;pdf.addImage(canvas.toDataURL('image/png'),'PNG',10,10,pw,ih);pdf.save('Image_Transcription.pdf');toast('PDF ready.');}catch{toast('PDF error.',true);}}
function downloadReaderDocx(){const text=document.getElementById('readerResult').innerText;if(!text.trim()){toast('Nothing to export.',true);return;}const html=text.split('\n').map(l=>'<p>'+(esc(l)||'&nbsp;')+'</p>').join('');const doc='<!DOCTYPE html><html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:w="urn:schemas-microsoft-com:office:word" xmlns="http://www.w3.org/TR/REC-html40"><head><meta charset="UTF-8"><style>@page{size:letter;margin:2.54cm}body{font-family:Calibri,sans-serif;font-size:11pt;line-height:1.6}p{margin:3pt 0}</style></head><body>'+html+'</body></html>';const blob=new Blob(['\ufeff'+doc],{type:'application/msword'});const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download='Image_Transcription.doc';document.body.appendChild(a);a.click();setTimeout(()=>{document.body.removeChild(a);URL.revokeObjectURL(url);},250);toast('Word ready.');}
async function loadImageBank(){const container=document.getElementById('imageBankGrid');container.innerHTML='<div style="grid-column:1/-1;text-align:center;color:var(--text-muted);padding:40px">Loading...</div>';try{const cases=await loadHistory();const allImages=[];for(const c of cases){const imgs=extractImages(c.output||'');imgs.forEach(img=>allImages.push({...img,caseName:c.title||'Untitled',caseId:c.id}));}caseImages.forEach(img=>{if(!allImages.find(i=>i.dataUrl===img.dataUrl))allImages.push({...img,caseName:'Current session',caseId:null});});if(!allImages.length){container.innerHTML='<div style="grid-column:1/-1;text-align:center;color:var(--text-muted);padding:40px;border:2px dashed var(--border);border-radius:var(--radius)">No images found. Add images to cases to see them here.</div>';return;}container.innerHTML=allImages.map(img=>`<div class="mn-bank-item" onclick="openImgPreview('${img.dataUrl}')"><img src="${img.dataUrl}" alt="${esc(img.name)}"><div class="mn-bank-item-label">${esc(img.caseName)}</div></div>`).join('');}catch(e){container.innerHTML='<div style="grid-column:1/-1;color:var(--danger);padding:20px">Error loading images.</div>';}}
function toast(msg,err){const t=document.getElementById('toast');t.textContent=msg;t.className='mn-toast show'+(err?' error':'');setTimeout(()=>t.className='mn-toast',3000);}
function toggleInput(){const b=document.getElementById('inputBody'),tg=document.getElementById('inputToggle');const c=b.classList.toggle('collapsed');tg.classList.toggle('collapsed',c);document.getElementById('toggleLabel').textContent=c?'Show Notes':'Hide Notes';}
function toggleEditPanel(){const p=document.getElementById('editPanel');p.classList.toggle('active');if(p.classList.contains('active'))document.getElementById('editInstructions').focus();}

const EDIT_PROMPT='You are a medical documentation assistant.\nYou previously generated this report:\n\n{{CURRENT_REPORT}}\n\nChanges requested:\n\n{{EDIT_INSTRUCTIONS}}\n\nApply ONLY the requested changes. Keep everything else. Return FULL report as clean HTML.';

async function generateReport(){const text=document.getElementById('clinicalInput').value.trim();if(!text){toast('Enter notes first.',true);return;}if(text.length<30){toast('Too short.',true);return;}const saveType=currentSheetId;currentInput=text;savedDraft='';currentCaseType=saveType;localStorage.removeItem('draft_'+currentSheetId);document.getElementById('draftBanner').classList.remove('active');document.getElementById('loader').classList.add('active');document.getElementById('loaderText').textContent='Structuring — please wait...';document.getElementById('outputSection').classList.remove('active');document.getElementById('btnGenerate').disabled=true;try{const html=await callAPI(getActivePrompt().replace('{{USER_TEXT}}',text));const stamp='<div class="mn-doctor-stamp">'+getDoctorStampHTML()+'</div>';structuredText=html+stamp;reportGenerated=true;hasUnsavedEdits=false;document.getElementById('reportContent').innerHTML=structuredText;applyReportTypo();if(caseImages.length)syncImagesInReport();document.getElementById('outputSection').classList.add('active');document.getElementById('editHint').classList.add('active');const sh=curSheet();document.getElementById('outputTypeBadge').textContent=sh.name;document.getElementById('btnSaveEdits').style.display='none';document.getElementById('inputToggle').style.display='flex';document.getElementById('inputBody').classList.add('collapsed');document.getElementById('inputToggle').classList.add('collapsed');document.getElementById('toggleLabel').textContent='Show Notes';document.getElementById('btnFollowup').style.display='inline-flex';const title=extractTitle(html);const id=currentCaseId||('case_'+Date.now());currentCaseId=id;await saveCase(id,title,text,getLiveReportHTML(),saveType);renderSidebar();showChatToggle();loadChatForCase(currentCaseId);if(chatOpen)renderChatMessages();toast('Report generated.');document.getElementById('outputSection').scrollIntoView({behavior:'smooth',block:'start'});}catch(err){toast('Error: '+err.message,true);}finally{document.getElementById('loader').classList.remove('active');document.getElementById('btnGenerate').disabled=false;}}
async function applyEdit(){const ins=document.getElementById('editInstructions').value.trim();if(!ins){toast('Describe changes.',true);return;}document.getElementById('loader').classList.add('active');document.getElementById('loaderText').textContent='Applying changes — please wait...';document.getElementById('btnApplyEdit').disabled=true;document.getElementById('btnApplyEdit').textContent='Processing...';try{const html=await callAPI(EDIT_PROMPT.replace('{{CURRENT_REPORT}}',getLiveReportHTML()).replace('{{EDIT_INSTRUCTIONS}}',ins));structuredText=html;document.getElementById('reportContent').innerHTML=html;applyReportTypo();if(caseImages.length)syncImagesInReport();document.getElementById('editPanel').classList.remove('active');document.getElementById('editInstructions').value='';hasUnsavedEdits=false;if(currentCaseId){await saveCase(currentCaseId,extractTitle(html),currentInput,html,currentCaseType);renderSidebar();}toast('Applied.');}catch(err){toast('Error: '+err.message,true);}finally{document.getElementById('loader').classList.remove('active');document.getElementById('btnApplyEdit').disabled=false;document.getElementById('btnApplyEdit').textContent='Apply';}}
async function copyToClipboard(){const el=document.getElementById('reportContent'),h=el.innerHTML,pt=el.innerText;try{if(navigator.clipboard&&window.ClipboardItem){await navigator.clipboard.write([new ClipboardItem({'text/html':new Blob([h],{type:'text/html'}),'text/plain':new Blob([pt],{type:'text/plain'})})]);toast('Copied!');}else{await navigator.clipboard.writeText(pt);toast('Copied.');}}catch{toast('Copy failed.',true);}}
async function downloadPDF(){toast('Preparing PDF...');try{const canvas=await html2canvas(document.getElementById('reportContent'),{scale:2,useCORS:true,backgroundColor:document.documentElement.classList.contains('dark')?'#1a1d28':'#fff'});const{jsPDF}=window.jspdf;const pdf=new jsPDF('p','mm','a4');const pw=pdf.internal.pageSize.getWidth()-20,pH=pdf.internal.pageSize.getHeight()-20,ih=canvas.height*pw/canvas.width;if(ih<=pH)pdf.addImage(canvas.toDataURL('image/png'),'PNG',10,10,pw,ih);else{let sY=0;while(sY<canvas.height){const sH=Math.min(canvas.height-sY,canvas.width*pH/pw);const sl=document.createElement('canvas');sl.width=canvas.width;sl.height=sH;sl.getContext('2d').drawImage(canvas,0,sY,canvas.width,sH,0,0,canvas.width,sH);if(sY>0)pdf.addPage();pdf.addImage(sl.toDataURL('image/png'),'PNG',10,10,pw,sH*pw/canvas.width);sY+=sH;}}pdf.save(curSheet().name.replace(/\s/g,'_')+'_Report.pdf');toast('PDF ready.');}catch(e){toast('PDF error.',true);}}
function downloadDOCX(){try{const h=document.getElementById('reportContent').innerHTML;const sh=curSheet();const doc='<!DOCTYPE html><html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:w="urn:schemas-microsoft-com:office:word" xmlns="http://www.w3.org/TR/REC-html40"><head><meta charset="UTF-8"><style>@page{size:letter;margin:2.54cm}body{font-family:Calibri,sans-serif;font-size:11pt;line-height:1.6}h2{font-size:13pt;font-weight:bold;color:'+sh.color+';border-bottom:1px solid #ddd;padding-bottom:4pt}p{margin:3pt 0}strong{font-weight:bold}</style></head><body><div style="text-align:center;font-size:15pt;font-weight:bold;color:'+sh.color+';margin-bottom:12pt">'+esc(sh.name).toUpperCase()+'</div><hr style="border:1px solid #ddd;margin-bottom:16pt">'+h+'</body></html>';const blob=new Blob(['\ufeff'+doc],{type:'application/msword'});const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download=sh.name.replace(/\s/g,'_')+'_Report.doc';document.body.appendChild(a);a.click();setTimeout(()=>{document.body.removeChild(a);URL.revokeObjectURL(url);},250);toast('Word ready.');}catch{toast('Word error.',true);}}
function clearAll(){const txt=document.getElementById('clinicalInput').value;const rep=document.getElementById('reportContent').innerText||'';if(txt.length>50||rep.length>50){showConfirm('You have content in the editor. <strong>Clear everything?</strong> This cannot be undone.',ok=>{if(ok)doClearAll();});}else{doClearAll();}}
function doClearAll(){document.getElementById('clinicalInput').value='';document.getElementById('charCount').textContent='0';document.getElementById('reportContent').innerHTML='';document.getElementById('outputSection').classList.remove('active');document.getElementById('editHint').classList.remove('active');document.getElementById('editPanel').classList.remove('active');document.getElementById('btnSaveEdits').style.display='none';document.getElementById('saveIndicator').classList.remove('active');document.getElementById('draftBanner').classList.remove('active');document.getElementById('btnFollowup').style.display='none';document.getElementById('followupContainer').innerHTML='';document.getElementById('followupPromptArea').style.display='none';document.getElementById('medicalNotesContainer').innerHTML='';document.getElementById('medicalNotesPromptArea').style.display='none';savedDraft='';structuredText='';reportGenerated=false;currentCaseId=null;currentInput='';hasUnsavedEdits=false;followupCount=0;medicalNotesCount=0;clearCaseImages();document.getElementById('inputToggle').style.display='none';document.getElementById('inputBody').classList.remove('collapsed');if(chatOpen)minimizeChat();toast('Cleared.');}

/* ═══ CASE ASSISTANT CHAT ═══ */
let chatOpen=false,caseChats={},chatWidth=380;
function expandChat(){chatOpen=true;const p=document.getElementById('chatPanel');p.classList.remove('peeking');p.classList.add('expanded');if(window.innerWidth>768)p.style.width=chatWidth+'px';else p.style.width='100%';document.getElementById('mainArea').classList.add('chat-expanded');renderChatMessages();setTimeout(()=>document.getElementById('chatInput').focus(),300);}
function minimizeChat(){chatOpen=false;const p=document.getElementById('chatPanel');p.classList.remove('expanded');p.classList.add('peeking');p.style.width='';document.getElementById('mainArea').classList.remove('chat-expanded');}
function toggleMobileChat(){if(chatOpen){minimizeChat();}else{expandChat();}}
function toggleChat(){if(chatOpen)minimizeChat();else expandChat();}
function showChatToggle(){}
/* Resize drag */
(function(){const handle=document.getElementById('chatResize');if(!handle)return;let dragging=false,startX,startW;handle.addEventListener('mousedown',e=>{dragging=true;startX=e.clientX;startW=document.getElementById('chatPanel').offsetWidth;document.body.style.cursor='col-resize';document.body.style.userSelect='none';e.preventDefault();});document.addEventListener('mousemove',e=>{if(!dragging)return;const diff=startX-e.clientX;const nw=Math.min(600,Math.max(260,startW+diff));document.getElementById('chatPanel').style.width=nw+'px';chatWidth=nw;});document.addEventListener('mouseup',()=>{if(dragging){dragging=false;document.body.style.cursor='';document.body.style.userSelect='';}});})();
function getCaseChat(){if(!currentCaseId)return[];if(!caseChats[currentCaseId])caseChats[currentCaseId]=[];return caseChats[currentCaseId];}
function copyChatMsg(idx){const msgs=getCaseChat();const m=msgs[idx];if(!m)return;navigator.clipboard.writeText(m.text).then(()=>toast('Copied.')).catch(()=>toast('Copy failed.',true));}
function renderChatMessages(){const el=document.getElementById('chatMessages');const msgs=getCaseChat();if(!msgs.length||!currentCaseId){el.innerHTML='<div class="mn-chat-empty"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M21 15a2 2 0 01-2 2H7l-4 4V5a2 2 0 012-2h14a2 2 0 012 2z"/></svg><br>'+(currentCaseId?'Ask me anything about this case.':'Generate a report first.')+'</div>';return;}
el.innerHTML=msgs.map((m,i)=>{if(m.role==='user')return'<div class="mn-chat-msg user">'+esc(m.text)+'</div>';
return'<div class="mn-chat-msg ai">'+(m.html||esc(m.text))+'<button class="mn-chat-copy" onclick="copyChatMsg('+i+')" title="Copy"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="9" y="9" width="13" height="13" rx="2"/><path d="M5 15H4a2 2 0 01-2-2V4a2 2 0 012-2h9a2 2 0 012 2v1"/></svg> Copy</button></div>';}).join('');el.scrollTop=el.scrollHeight;}
async function sendChat(){const inp=document.getElementById('chatInput');const text=inp.value.trim();if(!text)return;if(!currentCaseId||!reportGenerated){toast('Generate a report first.',true);return;}
if(!chatOpen)expandChat();
const msgs=getCaseChat();msgs.push({role:'user',text});inp.value='';renderChatMessages();
const el=document.getElementById('chatMessages');el.innerHTML+='<div class="mn-chat-msg ai typing">Thinking...</div>';el.scrollTop=el.scrollHeight;
document.getElementById('chatSendBtn').disabled=true;
try{const reportText=document.getElementById('reportContent').innerText||'';
const history=msgs.filter(m=>m.role).slice(-10).map(m=>({role:m.role==='user'?'user':'assistant',content:m.text}));
const sysContent='You are a medical case assistant. Answer questions about the case based on the report below. Be helpful, precise, professional medical language. Do NOT modify the report. Only provide information, analysis, recommendations.\n\nREPORT:\n'+reportText;
const apiMsgs=[{role:'user',content:sysContent},...history];
const r=await fetch(PROXY,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({model:'claude-sonnet-4-20250514',max_tokens:2048,messages:apiMsgs})});
if(!r.ok)throw new Error('API error '+r.status);
const d=await r.json();let reply=d.content.map(b=>b.text||'').join('');
const html=reply.replace(/\*\*(.*?)\*\*/g,'<strong>$1</strong>').replace(/\n- /g,'\n• ').replace(/\n/g,'<br>');
msgs.push({role:'ai',text:reply,html});
saveChatForCase();renderChatMessages();
}catch(e){msgs.push({role:'ai',text:'Error: '+e.message,html:'Error: '+esc(e.message)});renderChatMessages();}
document.getElementById('chatSendBtn').disabled=false;}
function saveChatForCase(){if(!currentCaseId)return;try{const all=JSON.parse(localStorage.getItem('mn_chats')||'{}');all[currentCaseId]=getCaseChat();localStorage.setItem('mn_chats',JSON.stringify(all));}catch{}}
function loadChatForCase(caseId){try{const all=JSON.parse(localStorage.getItem('mn_chats')||'{}');caseChats[caseId]=all[caseId]||[];}catch{caseChats[caseId]=[];}}

/* ═══ READ ALOUD ═══ */
let ttsUtterance=null,ttsReading=false;
function toggleReadAloud(){
if(ttsReading){speechSynthesis.cancel();ttsReading=false;document.getElementById('readLabel').textContent='Read Aloud';document.getElementById('btnReadAloud').classList.remove('mn-btn-danger');document.getElementById('btnReadAloud').classList.add('mn-btn-outline');return;}
const text=document.getElementById('reportContent').innerText||'';
if(!text.trim()){toast('No report to read.',true);return;}
ttsUtterance=new SpeechSynthesisUtterance(text);
ttsUtterance.lang='en-US';ttsUtterance.rate=0.95;ttsUtterance.pitch=1;
const voices=speechSynthesis.getVoices();
const enVoice=voices.find(v=>v.lang.startsWith('en')&&v.name.includes('Google'))||voices.find(v=>v.lang.startsWith('en'))||null;
if(enVoice)ttsUtterance.voice=enVoice;
ttsUtterance.onstart=()=>{ttsReading=true;document.getElementById('readLabel').textContent='Stop Reading';document.getElementById('btnReadAloud').classList.remove('mn-btn-outline');document.getElementById('btnReadAloud').classList.add('mn-btn-danger');};
ttsUtterance.onend=()=>{ttsReading=false;document.getElementById('readLabel').textContent='Read Aloud';document.getElementById('btnReadAloud').classList.remove('mn-btn-danger');document.getElementById('btnReadAloud').classList.add('mn-btn-outline');};
ttsUtterance.onerror=()=>{ttsReading=false;document.getElementById('readLabel').textContent='Read Aloud';document.getElementById('btnReadAloud').classList.remove('mn-btn-danger');document.getElementById('btnReadAloud').classList.add('mn-btn-outline');};
speechSynthesis.speak(ttsUtterance);}
if(typeof speechSynthesis!=='undefined')speechSynthesis.getVoices();

/* ═══ DRAFT AUTO-SAVE ═══ */
function autoSaveDraft(){const txt=document.getElementById('clinicalInput').value.trim();if(txt&&!reportGenerated){localStorage.setItem('draft_'+currentSheetId,txt);}else{localStorage.removeItem('draft_'+currentSheetId);}}
document.getElementById('clinicalInput').addEventListener('input',function(){document.getElementById('charCount').textContent=this.value.length;if(!reportGenerated)localStorage.setItem('draft_'+currentSheetId,this.value);});

/* ═══ WELCOME SCREEN ═══ */
function renderWelcome(){const g=document.getElementById('welcomeGrid');g.innerHTML=S.sheets.map(sh=>'<div class="mn-welcome-card" onclick="startFromWelcome(\''+sh.id+'\')"><div class="wc-dot" style="background:'+sh.color+'"></div><div class="wc-name">'+esc(sh.name)+'</div><div class="wc-desc">Start a new report</div></div>').join('');renderRecentCases();}
async function renderRecentCases(){const container=document.getElementById('recentCasesList');if(!container)return;const cases=await loadHistory();const recent=cases.slice().sort((a,b)=>(b.timestamp||0)-(a.timestamp||0)).slice(0,9);const search=(document.getElementById('recentSearch')?.value||'').trim().toLowerCase();let filtered=recent;if(search)filtered=recent.filter(c=>{const hay=((c.title||'')+' '+(c.input||'')+' '+(c.output||'')+' '+(c.type||'')).toLowerCase();return hay.includes(search);});if(!filtered.length){container.innerHTML='<div class="mn-recent-empty">'+(recent.length?'No matching cases.':'No cases yet. Start a new report above.')+'</div>';return;}const bookmarks=getBookmarks();container.innerHTML=filtered.map(c=>{const d=new Date(c.timestamp),ds=d.toLocaleDateString('en-US',{month:'short',day:'numeric'}),ts=d.toLocaleTimeString('en-US',{hour:'2-digit',minute:'2-digit'});const type=c.type||'notes';const sh=getSheet(type);const color=sh?sh.color:'#888';const label=sh?sh.name:type;const meta=extractMeta(c.output||'');const patientName=(meta.name&&meta.name!=='Not provided')?meta.name:(c.title||'Untitled');const age=(meta.age&&meta.age!=='Not provided')?meta.age:'';const complaint=(meta.complaint&&meta.complaint!=='Not provided')?meta.complaint:'';const isBookmarked=bookmarks.includes(c.id);const starClass=isBookmarked?'mn-recent-star active':'mn-recent-star';const starTitle=isBookmarked?'Remove bookmark':'Save bookmark';return '<div class="mn-recent-card" onclick="loadCase(\''+c.id+'\')" style="border-top:3px solid '+color+'"><div class="mn-recent-card-top"><span class="mn-recent-badge" style="background:'+color+'22;color:'+color+'">'+esc(label)+'</span><button class="'+starClass+'" onclick="event.stopPropagation();toggleRecentBookmark(\''+c.id+'\')" title="'+starTitle+'">&#9733;</button></div><div class="mn-recent-card-name">'+esc(patientName)+'</div>'+(age?'<div class="mn-recent-card-age">Age: '+esc(age)+'</div>':'')+(complaint?'<div class="mn-recent-card-cc"><span class="mn-recent-cc-label">CC</span> '+esc(complaint)+'</div>':'')+'<div class="mn-recent-card-date">'+ds+' · '+ts+'</div></div>';}).join('');}
function toggleRecentBookmark(id){toggleBookmarkCase(id);renderRecentCases();}function filterRecentCases(){renderRecentCases();}function startFromWelcome(sheetId){switchMode(sheetId);newCase();}
function showWelcome(){hideSpecialPanels();document.querySelectorAll('#tabNotepad,#tabImageReader,#tabImageBank').forEach(b=>b.classList.remove('active'));document.getElementById('welcomeScreen').style.display='block';document.getElementById('mainWorkarea').style.display='none';renderRecentCases();}
/* ═══ PERSONAL NOTES ═══ */
function savePersonalNote(){if(!currentCaseId)return;const t=document.getElementById('personalNotes').value;try{const all=JSON.parse(localStorage.getItem('mn_pnotes')||'{}');all[currentCaseId]=t;localStorage.setItem('mn_pnotes',JSON.stringify(all));}catch{}}
function loadPersonalNote(){const el=document.getElementById('personalNotes');if(!currentCaseId){el.value='';return;}try{const all=JSON.parse(localStorage.getItem('mn_pnotes')||'{}');el.value=all[currentCaseId]||'';}catch{el.value='';}}

/* ═══ BOOKMARKS ═══ */
function getBookmarks(){try{return JSON.parse(localStorage.getItem('mn_bookmarks')||'[]');}catch{return[];}}
function setBookmarks(b){localStorage.setItem('mn_bookmarks',JSON.stringify(b));}
function toggleBookmarkCase(id){let b=getBookmarks();if(b.includes(id))b=b.filter(x=>x!==id);else b.push(id);setBookmarks(b);renderBookmarks();renderFullHistory();}
function toggleBookmarks(){const l=document.getElementById('bookmarksList');l.classList.toggle('open');if(l.classList.contains('open'))renderBookmarks();}
async function renderBookmarks(){const bm=getBookmarks();document.getElementById('bookmarkCount').textContent='('+bm.length+')';const l=document.getElementById('bookmarksList');if(!bm.length){l.innerHTML='<div class="mn-sidebar-empty" style="padding:12px;font-size:.72rem">No saved cases.</div>';return;}
const cases=await loadHistory();const saved=cases.filter(c=>bm.includes(c.id));l.innerHTML=saved.map(c=>{const sh=getSheet(c.type||'notes');const color=sh?sh.color:'#888';return'<div class="mn-sidebar-item" onclick="loadCase(\''+c.id+'\')"><div class="mn-sidebar-item-title"><span class="mn-type-badge" style="background:'+color+'22;color:'+color+'">&#9733;</span>'+esc(c.title||'Untitled')+'</div></div>';}).join('');}

/* ═══ FULL HISTORY MODAL ═══ */
function openFullHistory(){updateFHFilters();renderFullHistory();document.getElementById('fullHistOverlay').classList.add('active');}
function closeFullHistory(){document.getElementById('fullHistOverlay').classList.remove('active');}
function updateFHFilters(){const sel=document.getElementById('fhFilterType');sel.innerHTML='<option value="all">All Types</option>'+S.sheets.map(sh=>'<option value="'+sh.id+'">'+esc(sh.name)+'</option>').join('');}
async function renderFullHistory(){const cases=await loadHistory();const fType=document.getElementById('fhFilterType').value;const fSearch=(document.getElementById('fhSearch').value||'').toLowerCase();const fFrom=document.getElementById('fhFrom').value;const fTo=document.getElementById('fhTo').value;const bm=getBookmarks();
let filtered=cases;if(fType&&fType!=='all')filtered=filtered.filter(c=>(c.type||'notes')===fType);if(fFrom)filtered=filtered.filter(c=>c.timestamp>=new Date(fFrom).getTime());if(fTo)filtered=filtered.filter(c=>c.timestamp<new Date(fTo).getTime()+86400000);if(fSearch)filtered=filtered.filter(c=>((c.title||'')+(c.input||'')).toLowerCase().includes(fSearch));
const l=document.getElementById('fhList');if(!filtered.length){l.innerHTML='<div style="text-align:center;padding:40px;color:var(--text-muted)">No cases found.</div>';return;}
l.innerHTML=filtered.map(c=>{const d=new Date(c.timestamp);const ds=d.toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric',hour:'2-digit',minute:'2-digit'});const sh=getSheet(c.type||'notes');const color=sh?sh.color:'#888';const isBm=bm.includes(c.id);
return'<div class="mn-fullhist-item" onclick="loadCase(\''+c.id+'\');closeFullHistory()"><span class="mn-type-badge" style="background:'+color+'22;color:'+color+';flex-shrink:0">'+(sh?sh.name.substring(0,4).toUpperCase():'NOTE')+'</span><div class="mn-fullhist-item-info"><div class="mn-fullhist-item-title">'+esc(c.title||'Untitled')+'</div><div class="mn-fullhist-item-date">'+ds+'</div></div><div class="mn-fullhist-item-btns" onclick="event.stopPropagation()"><button class="mn-fh-bookmark'+(isBm?' saved':'')+'" onclick="toggleBookmarkCase(\''+c.id+'\')" title="'+(isBm?'Remove bookmark':'Bookmark')+'">&#9733;</button><button style="background:var(--danger-light);color:var(--danger)" onclick="deleteCaseUI(\''+c.id+'\');renderFullHistory()">Del</button></div></div>';}).join('');}

/* ═══ FOLLOW-UP REPORTS ═══ */
let followupCount=0;
function showFollowupPrompt(){document.getElementById('followupPromptArea').style.display='block';attachMiniMic('followupInstructions');document.getElementById('followupInstructions').focus();document.getElementById('followupPromptArea').scrollIntoView({behavior:'smooth'});}function hideFollowupPrompt(){document.getElementById('followupPromptArea').style.display='none';}
async function generateFollowup(){const instructions=document.getElementById('followupInstructions').value.trim();if(!instructions){toast('Describe what this follow-up should contain.',true);return;}
const prevReport=document.getElementById('reportContent').innerText||'';
document.getElementById('loader').classList.add('active');document.getElementById('loaderText').textContent='Generating follow-up — please wait...';
try{const prompt='You are a medical documentation assistant.\nBased on the PREVIOUS REPORT below, generate a NEW follow-up report as requested.\n\nPREVIOUS REPORT:\n'+prevReport+'\n\nUSER REQUEST:\n'+instructions+'\n\nRULES:\n- Generate ONLY the requested content as a NEW standalone report section.\n- Use clean HTML: <h2> for titles, <p> for content, <strong> for labels.\n- Professional medical language.\n- Do NOT repeat the entire previous report, only the new requested content.\n\nOUTPUT: Return the follow-up report as HTML.';
const html=await callAPI(prompt);followupCount++;
const fid='followup_'+followupCount;
const container=document.getElementById('followupContainer');
container.insertAdjacentHTML('beforeend','<div class="mn-followup-section" id="'+fid+'"><div class="mn-output-label">Follow-up Report #'+followupCount+' <span class="mn-badge mn-badge-ready">Ready</span></div><div class="mn-card"><div class="mn-report" contenteditable="true" spellcheck="true">'+html+'</div><div class="mn-actions" style="margin-top:12px;border-top:1px solid var(--border);padding-top:10px"><button class="mn-btn mn-btn-outline" onclick="copyFollowup(\''+fid+'\')" style="font-size:.78rem;padding:7px 14px">Copy</button><button class="mn-btn mn-btn-outline" onclick="downloadFollowupPDF(\''+fid+'\')" style="font-size:.78rem;padding:7px 14px">PDF</button><button class="mn-btn mn-btn-outline" onclick="readFollowup(\''+fid+'\')" style="font-size:.78rem;padding:7px 14px">Read</button></div></div></div>');
document.getElementById('followupPromptArea').style.display='none';document.getElementById('followupInstructions').value='';
document.getElementById(fid).scrollIntoView({behavior:'smooth'});toast('Follow-up generated.');
}catch(err){toast('Error: '+err.message,true);}finally{document.getElementById('loader').classList.remove('active');}}
function copyFollowup(fid){const el=document.querySelector('#'+fid+' .mn-report');if(!el)return;navigator.clipboard.writeText(el.innerText).then(()=>toast('Copied.')).catch(()=>toast('Copy failed.',true));}
async function downloadFollowupPDF(fid){const el=document.querySelector('#'+fid+' .mn-report');if(!el)return;toast('Preparing PDF...');try{const canvas=await html2canvas(el,{scale:2,backgroundColor:'#fff'});const{jsPDF}=window.jspdf;const pdf=new jsPDF('p','mm','a4');const pw=pdf.internal.pageSize.getWidth()-20;const ih=canvas.height*pw/canvas.width;pdf.addImage(canvas.toDataURL('image/png'),'PNG',10,10,pw,ih);pdf.save('Followup_Report.pdf');toast('PDF ready.');}catch{toast('PDF error.',true);}}
function readFollowup(fid){const el=document.querySelector('#'+fid+' .mn-report');if(!el)return;const text=el.innerText;const u=new SpeechSynthesisUtterance(text);u.lang='en-US';u.rate=0.95;speechSynthesis.speak(u);}

