function deleteMedicalNotes(mnid){showConfirm('Delete this Medical Note?',ok=>{if(ok){const el=document.getElementById(mnid);if(el)el.remove();toast('Medical Note deleted.');}});}
function applyReportTypoTo(rep){if(!rep)return;const sh=curSheet();const t=sh.options?.typo||{h2:{size:16,bold:true,color:'#000000',underline:false},strong:{size:14,bold:true,color:'#000000',underline:false},p:{size:14,bold:false,color:'#000000',underline:false}};const h2=typeof t.h2==='number'?{size:t.h2,bold:true,color:'#000000',underline:false}:t.h2;const st=typeof t.strong==='number'?{size:t.strong,bold:true,color:'#000000',underline:false}:t.strong;const pp=typeof t.p==='number'?{size:t.p,bold:false,color:'#000000',underline:false}:t.p;rep.querySelectorAll('h2').forEach(el=>{el.style.fontSize=h2.size+'px';el.style.fontWeight=h2.bold?'700':'400';el.style.color=h2.color||'';el.style.textDecoration=h2.underline?'underline':'none';});rep.querySelectorAll('strong').forEach(el=>{el.style.fontSize=st.size+'px';el.style.fontWeight=st.bold?'700':'400';el.style.color=st.color||'';el.style.textDecoration=st.underline?'underline':'none';});rep.querySelectorAll('p').forEach(el=>{el.style.fontSize=pp.size+'px';el.style.fontWeight=pp.bold?'700':'400';el.style.color=pp.color||'';el.style.textDecoration=pp.underline?'underline':'none';});}

